func (s *Server) listCommand(user *User) {
	s.mutex.RLock()
	defer s.mutex.RUnlock()

	var userList strings.Builder
	userList.WriteString("Online users:\n")
	for username, u := range s.users {
		userList.WriteString(fmt.Sprintf("- %s [%s]\n", username, u.Role))
	}

	s.sendMessage(user.Conn, CommandResult{
		Success: true,
		Message: userList.String(),
	})
}

func (s *Server) helpCommand(user *User) {
	help := "Available commands:\n"
	help += "/help - Show this help message\n"
	help += "/list - List online users\n"
	
	if user.Role == RoleModerator || user.Role == RoleAdmin {
		help += "/kick <username> - Kick a user\n"
		help += "/giveitems <username> <items> - Give items to a user\n"
	}
	
	if user.Role == RoleAdmin {
		help += "/ban <username> [minutes] - Ban a user\n"
		help += "/promote <username> - Promote a user\n"
		help += "/demote <username> - Demote a user\n"
	}

	s.sendMessage(user.Conn, CommandResult{
		Success: true,
		Message: help,
	})
}

func (s *Server) broadcast(msg Message) {
	s.mutex.RLock()
	defer s.mutex.RUnlock()

	for _, user := range s.users {
		s.sendMessage(user.Conn, msg)
	}
}

func (s *Server) sendMessage(conn net.Conn, data interface{}) {
	jsonData, err := json.Marshal(data)
	if err != nil {
		log.Printf("Error marshaling message: %v", err)
		return
	}

	conn.Write(append(jsonData, '\n'))
}

func main() {
	server := NewServer()
	log.Fatal(server.Start("8080"))
}